import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        Node[] child = new Node[26];
        boolean end;
    }

    static void insert(Node root, String s) {
        Node cur = root;
        for (char c : s.toCharArray()) {
            int idx = c - 'a';
            if (cur.child[idx] == null) cur.child[idx] = new Node();
            cur = cur.child[idx];
        }
        cur.end = true;
    }

    static void collect(Node node, StringBuilder sb, List<String> out) {
        if (node.end) out.add(sb.toString());
        for (int i = 0; i < 26; i++) {
            if (node.child[i] != null) {
                sb.append((char) ('a' + i));
                collect(node.child[i], sb, out);
                sb.setLength(sb.length() - 1);
            }
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String firstLine = br.readLine();
        if (firstLine == null) return; // no input
        firstLine = firstLine.trim();
        if (firstLine.isEmpty()) return;
        int T = Integer.parseInt(firstLine);
        StringBuilder finalOutput = new StringBuilder();
        for (int t = 0; t < T; t++) {
            // read N
            String line;
            do { line = br.readLine(); } while (line != null && line.trim().isEmpty());
            if (line == null) break;
            int N = Integer.parseInt(line.trim());
            // read prefix S
            String S = br.readLine();
            if (S == null) S = ""; else S = S.trim();
            Node root = new Node();
            for (int i = 0; i < N; i++) {
                String w = br.readLine();
                if (w == null) w = "";
                w = w.trim();
                insert(root, w);
            }
            // navigate to node of prefix
            Node cur = root;
            boolean ok = true;
            for (char c : S.toCharArray()) {
                int idx = c - 'a';
                if (cur.child[idx] == null) { ok = false; break; }
                cur = cur.child[idx];
            }
            List<String> matches = new ArrayList<>();
            if (ok) {
                StringBuilder sb = new StringBuilder(S);
                collect(cur, sb, matches);
            }
            // build output with literal "\\n"
            StringBuilder caseOut = new StringBuilder();
            for (int i = 0; i < matches.size(); i++) {
                caseOut.append(matches.get(i));
                if (i + 1 < matches.size()) caseOut.append("\\n");
            }
            finalOutput.append(caseOut);
            if (t != T - 1) finalOutput.append('\n'); // separate test cases with real newline
        }
        System.out.print(finalOutput.toString());
    }
}

